import React from 'react';
import ReactDOM from 'react-dom/client';

// Create your components
function Header() {
  return <header><h1>My Website</h1></header>;
}

function Main() {
  return <main><p>Welcome to my React app!</p></main>;
}

function Footer() {
  return <footer><p>© 2024</p></footer>;
}

// Combine in App
function App() {
  return (
    <div>
      <Header />
      <Main />
      <Footer />
    </div>
  );
}

// Get the root and render
const container = document.getElementById('root');
const root = ReactDOM.createRoot(container);
root.render(<App />);
